@import '../../utils/focus-ring.css';
@import '../../utils/control-inactive.css';

/**
 * Swatch — 24×24 orb (size-300). Spacing lives on the picker row.
 *
 * Layer stack (bottom → top):
 *   Default:    fill → border → interaction (hover/press)
 *   Selected:   fill → border → interaction → halo → stroke (brand)
 */

:host {
  box-sizing: border-box;
  display: inline-flex;
  flex: 0 0 auto;
  width: var(--dimension-size-300);
  height: var(--dimension-size-300);
  --_swatch-inner-inset: calc(
    var(--dimension-stroke-width-025) + var(--dimension-space-025)
  );
  --_swatch-ring-bg: var(--color-background-primary);
  --_swatch-select-motion: var(--effect-motion-short-3);
}

.shell-gradient-swatch {
  position: relative;
  box-sizing: border-box;
  width: var(--dimension-size-300);
  height: var(--dimension-size-300);
  padding: 0;
  border: none;
  border-radius: var(--dimension-radius-half);
  background: transparent;
  cursor: pointer;
  flex-shrink: 0;
  isolation: isolate;
}

.shell-gradient-swatch__fill,
.shell-gradient-swatch__border,
.shell-gradient-swatch__interaction,
.shell-gradient-swatch__halo,
.shell-gradient-swatch__stroke {
  position: absolute;
  top: 0;
  right: 0;
  bottom: 0;
  left: 0;
  border-radius: inherit;
  pointer-events: none;
}

/* 1 — fill */
.shell-gradient-swatch__fill {
  z-index: 1;
  background-color: var(--color-background-secondary);
  background-image: var(--_swatch-gradient-image);
  background-repeat: no-repeat;
  background-size: cover;
  background-position: 0 0;
  transition:
    top var(--_swatch-select-motion),
    right var(--_swatch-select-motion),
    bottom var(--_swatch-select-motion),
    left var(--_swatch-select-motion);
}

.shell-gradient-swatch--none .shell-gradient-swatch__fill {
  background-image: none;
}

.shell-gradient-swatch:not(.shell-gradient-swatch--none) .shell-gradient-swatch__fill {
  opacity: var(--ds-shell-gradient-opacity, 0.1);
}

/* 2 — secondary border (matches ds-interaction-fill--bordered) */
.shell-gradient-swatch__border {
  z-index: 2;
  box-shadow: inset 0 0 0 var(--dimension-stroke-width-012) var(--color-border-secondary);
  transition:
    top var(--_swatch-select-motion),
    right var(--_swatch-select-motion),
    bottom var(--_swatch-select-motion),
    left var(--_swatch-select-motion);
}

/* 3 — hover / press (over border, under selected chrome) */
.shell-gradient-swatch__interaction {
  z-index: 3;
  background: transparent;
  transition:
    top var(--_swatch-select-motion),
    right var(--_swatch-select-motion),
    bottom var(--_swatch-select-motion),
    left var(--_swatch-select-motion),
    background-color 0s;
}

.shell-gradient-swatch:hover:not(:disabled) .shell-gradient-swatch__interaction {
  background: var(--color-interaction-hover);
}

.shell-gradient-swatch:active:not(:disabled) .shell-gradient-swatch__interaction {
  background: var(--color-interaction-pressed);
}

/* 4 — halo gap (selected only) */
.shell-gradient-swatch__halo {
  z-index: 4;
  opacity: 0;
  transform: scale(1.2);
  transform-origin: center;
  box-shadow: inset 0 0 0 var(--_swatch-inner-inset) var(--_swatch-ring-bg);
  transition:
    opacity var(--_swatch-select-motion),
    transform var(--_swatch-select-motion);
}

/* 5 — brand stroke (selected only) */
.shell-gradient-swatch__stroke {
  z-index: 5;
  opacity: 0;
  transform: scale(1.2);
  transform-origin: center;
  box-shadow: inset 0 0 0 var(--dimension-stroke-width-025) var(--color-border-bold-brand);
  transition:
    opacity var(--_swatch-select-motion),
    transform var(--_swatch-select-motion);
}

.shell-gradient-swatch--selected .shell-gradient-swatch__fill,
.shell-gradient-swatch--selected .shell-gradient-swatch__border,
.shell-gradient-swatch--selected .shell-gradient-swatch__interaction {
  top: var(--_swatch-inner-inset);
  right: var(--_swatch-inner-inset);
  bottom: var(--_swatch-inner-inset);
  left: var(--_swatch-inner-inset);
}

.shell-gradient-swatch--selected .shell-gradient-swatch__halo,
.shell-gradient-swatch--selected .shell-gradient-swatch__stroke {
  opacity: 1;
  transform: scale(1);
}

/* Inactive: `.ds-control-inactive` (25% opacity). */

@media (prefers-reduced-motion: reduce) {
  .shell-gradient-swatch__fill,
  .shell-gradient-swatch__border,
  .shell-gradient-swatch__interaction,
  .shell-gradient-swatch__halo,
  .shell-gradient-swatch__stroke {
    transition: none;
  }
}

import { Component, Prop, Event, EventEmitter, h, Host } from '@stencil/core';
import {
  SHELL_GRADIENT_PRESET_LABELS,
  buildShellRadialGradientForPreset,
  DEFAULT_SHELL_GRADIENT_PRESET,
  type ShellGradientPreset,
} from './shell-gradient-swatch-types';
import { shellGradientPresetOpacity } from '../../shell/shell-gradient-presets';

/** @deprecated Use `ds-swatch-picker`; individual swatches are implementation detail. */
@Component({
  tag: 'ds-shell-gradient-swatch',
  styleUrl: 'ShellGradientSwatch.css',
  scoped: true,
})
export class ShellGradientSwatch {
  /** Wash preset this orb previews. */
  @Prop({ reflect: true }) preset: ShellGradientPreset = DEFAULT_SHELL_GRADIENT_PRESET;

  /** Selected — brand stroke + halo over inner fill/border/interaction stack. */
  @Prop({ reflect: true }) selected = false;

  @Prop() isInactive = false;

  @Prop({ attribute: 'aria-label' }) ariaLabel: string | null = null;

  @Event() dsSelect!: EventEmitter<ShellGradientPreset>;

  private handleClick = () => {
    if (this.isInactive) return;
    this.dsSelect.emit(this.preset);
  };

  render() {
    const label = this.ariaLabel ?? SHELL_GRADIENT_PRESET_LABELS[this.preset];

    return (
      <Host>
        <button
          type="button"
          class={{
            'shell-gradient-swatch': true,
            'ds-focus-ring-inset': true,
            'ds-control-inactive': this.isInactive,
            'shell-gradient-swatch--selected': this.selected,
            'shell-gradient-swatch--none': this.preset === 'none',
          }}
          style={
            this.preset === 'none'
              ? undefined
              : {
                  '--_swatch-gradient-image': buildShellRadialGradientForPreset(this.preset),
                  '--ds-shell-gradient-opacity': shellGradientPresetOpacity(this.preset),
                }
          }
          aria-label={label}
          role="radio"
          aria-checked={this.selected ? 'true' : 'false'}
          tabIndex={this.selected ? 0 : -1}
          disabled={this.isInactive}
          onClick={this.handleClick}
        >
          <span class="shell-gradient-swatch__fill" aria-hidden="true" />
          <span class="shell-gradient-swatch__border" aria-hidden="true" />
          <span class="shell-gradient-swatch__interaction" aria-hidden="true" />
          <span class="shell-gradient-swatch__halo" aria-hidden="true" />
          <span class="shell-gradient-swatch__stroke" aria-hidden="true" />
        </button>
      </Host>
    );
  }
}

import type { ShellGradientPreset } from '../../shell/shell-gradient-presets';
export type { ShellGradientPreset };

export {
  DEFAULT_SHELL_GRADIENT_PRESET,
  SHELL_GRADIENT_PRESETS,
  SHELL_GRADIENT_WASH_PRESETS,
  SHELL_GRADIENT_PRESET_LABELS,
  buildShellRadialGradientForPreset,
  buildShellRadialGradientFromStops,
  isShellGradientPreset,
  normalizeShellGradientPreset,
  shellGradientPresetOpacity,
  shellGradientPresetRecipe,
  shellGradientPresetStopToken,
} from '../../shell/shell-gradient-presets';
